import{_ as a,c as e,o as m,b as t}from"./app.56f378f3.js";const l='{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 8","description":"","frontmatter":{"title":"\u0410\u0444\u043E\u0440\u0438\u0437\u043C 8","subtitle":"\u0428\u0438\u0432\u0430 \u0441\u0443\u0442\u0440\u0430 \u0432\u0438\u043C\u0430\u0440\u0448\u0438\u043D\u0438. \u0413\u043B\u0430\u0432\u0430 2.","tags":"vim-2","date":"2021-02-03T00:00:00.000Z"},"headers":[],"relativePath":"texts/shiva-sutra-vimarshini/2/8/index.md"}',o={},i=t('<div class="stanza"><a href="#s2.8" id="s2.8" class="num">2.8</a><div class="sans"><p>\u0908\u0926\u0943\u0936\u0938\u094D\u092F\u093E\u0938\u094D\u092F \u092E\u093E\u0924\u0943\u0915\u093E\u091A\u0915\u094D\u0930\u0938\u092E\u094D\u092C\u094B\u0927\u0935\u0924\u0903\u2014</p><blockquote><p><strong>\u0936\u0930\u0940\u0930\u0902 \u0939\u0935\u093F\u0903\u0965\u096E\u0965</strong></p></blockquote><p>\u0938\u0930\u094D\u0935\u0948\u0930\u094D\u092F\u0924\u094D\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u094D\u0935\u0947\u0928\u093E\u092D\u093F\u0937\u093F\u0915\u094D\u0924\u0902 \u0938\u094D\u0925\u0942\u0932\u0938\u0942\u0915\u094D\u0937\u094D\u092E\u093E\u0926\u093F\u0938\u094D\u0935\u0930\u0942\u092A\u0902 \u0936\u0930\u0940\u0930\u0902 \u0924\u0928\u094D \u092E\u0939\u093E\u092F\u094B\u0917\u093F\u0928\u0903 \u092A\u0930\u0938\u094D\u092E\u093F\u0902\u0936\u094D\u091A\u093F\u0926\u0917\u094D\u0928\u094C \u0939\u0942\u092F\u092E\u093E\u0928\u0902 \u0939\u0935\u093F\u0903 \u0936\u0930\u0940\u0930\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u093E\u092A\u094D\u0930\u0936\u092E\u0928\u0947\u0928 \u0938\u0926\u0948\u0935 \u091A\u093F\u0928\u094D\u092E\u093E\u0924\u0943\u0924\u093E\u092D\u093F\u0928\u093F\u0935\u093F\u0937\u094D\u091F\u0924\u094D\u0935\u093E\u0924\u094D\u0964 \u092F\u0926\u0941\u0915\u094D\u0924\u0902 \u0936\u094D\u0930\u0940\u0935\u093F\u091C\u094D\u091E\u093E\u0928\u092D\u0948\u0930\u0935\u0947</p><blockquote><p>\u092E\u0939\u093E\u0936\u0942\u0928\u094D\u092F\u093E\u0932\u092F\u0947 \u0935\u0939\u094D\u0928\u094C \u092D\u0942\u0924\u093E\u0915\u094D\u0937\u0935\u093F\u0937\u092F\u093E\u0926\u093F\u0915\u092E\u094D\u0964<br> \u0939\u0942\u092F\u0924\u0947 \u092E\u0928\u0938\u093E \u0938\u093E\u0915\u0902 \u0938 \u0939\u094B\u092E\u0903 \u0938\u094D\u0930\u0941\u0915\u094D\u091A \u091A\u0947\u0924\u0928\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0936\u094D\u0930\u0940\u0924\u093F\u092E\u093F\u0930\u094B\u0926\u094D\u0918\u093E\u091F\u0947\u093D\u092A\u093F</p><blockquote><p>\u092F\u0903 \u092A\u094D\u0930\u093F\u092F\u094B \u092F\u0903 \u0938\u0941\u0939\u0943\u0926\u094D\u092C\u0928\u094D\u0927\u0941\u0930\u094D\u092F\u094B \u0926\u093E\u0924\u093E \u092F\u094B\u093D\u0924\u093F\u0935\u0932\u094D\u0932\u092D\u0903\u0964<br> \u0924\u0926\u0919\u094D\u0917\u092D\u0915\u094D\u0937\u0923\u093E\u0926\u094D\u0926\u0947\u0935\u093F \u0939\u094D\u092F\u0941\u0924\u094D\u092A\u0924\u0947\u0926\u094D\u0917\u0917\u0928\u093E\u0919\u094D\u0917\u0928\u093E\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0905\u0924\u094D\u0930 \u0939\u093F \u0926\u0947\u0939\u092A\u094D\u0930\u092E\u093E\u0924\u0943\u0924\u093E\u092A\u094D\u0930\u0936\u092E\u0928\u092E\u0947\u0935 \u092A\u093F\u0923\u094D\u0921\u093E\u0930\u094D\u0925\u0903\u0964 \u0936\u094D\u0930\u0940\u092E\u0926\u094D\u092D\u0917\u0935\u0926\u094D\u0917\u0940\u0924\u093E\u0938\u094D\u0935\u092A\u093F</p><blockquote><p>\u0938\u0930\u094D\u0935\u093E\u0923\u0940\u0928\u094D\u0926\u094D\u0930\u093F\u092F\u0915\u0930\u094D\u092E\u093E\u0923\u093F \u092A\u094D\u0930\u093E\u0923\u0915\u0930\u094D\u092E\u093E\u0923\u093F \u091A\u093E\u092A\u0930\u0947\u0964<br> \u0906\u0924\u094D\u092E\u0938\u0902\u092F\u092E\u092F\u094B\u0917\u093E\u0917\u094D\u0928\u094C \u091C\u0941\u0939\u094D\u0935\u0924\u093F \u091C\u094D\u091E\u093E\u0928\u0926\u0940\u092A\u093F\u0924\u0947\u0965</p></blockquote><p>\u0907\u0924\u093F\u0964 \u0938\u094D\u092A\u0928\u094D\u0926\u0947 \u0924\u0941</p><blockquote><p>\u092F\u0926\u093E \u0915\u094D\u0937\u094B\u092D\u0903 \u092A\u094D\u0930\u0932\u0940\u092F\u0947\u0924 \u0924\u0926\u093E \u0938\u094D\u092F\u093E\u0924\u094D\u092A\u0930\u092E\u0902 \u092A\u0926\u092E\u094D\u0964</p></blockquote><p>\u0907\u0924\u094D\u092F\u0928\u0947\u0928\u0948\u0935 \u0938\u0919\u094D\u0917\u0943\u0939\u0940\u0924\u092E\u094D\u0964 \u0915\u094D\u0937\u094B\u092D\u094B \u0926\u0947\u0939\u093E\u0926\u094D\u092F\u0939\u092E\u094D\u092A\u094D\u0930\u0924\u094D\u092F\u092F\u0930\u0942\u092A \u0907\u0924\u093F \u0939\u093F \u0924\u0926\u094D\u0935\u0943\u0924\u094D\u0924\u094C \u092D\u091F\u094D\u091F\u0936\u094D\u0930\u0940\u0915\u0932\u094D\u0932\u091F\u0903\u0965\u096E\u0965</p></div><hr><div class="trans"><p>\u012Ad\u1E5B\u015Basy\u0101sya m\u0101t\u1E5Bk\u0101cakrasambodhavata\u1E25\u2014</p><blockquote><p><strong>\u015Aar\u012Bra\u1E41 havi\u1E25||8||</strong></p></blockquote><p>Sarvairyatpram\u0101t\u1E5Btven\u0101bhi\u1E63ikta\u1E41 sth\u016Blas\u016Bk\u1E63m\u0101disvar\u016Bpa\u1E41 \u015Bar\u012Bra\u1E41 tan mah\u0101yogina\u1E25 parasmi\u1E41\u015Bcidagnau h\u016Byam\u0101na\u1E41 havi\u1E25 \u015Bar\u012Brapram\u0101t\u1E5Bt\u0101pra\u015Bamanena sadaiva cinm\u0101t\u1E5Bt\u0101bhinivi\u1E63\u1E6Datv\u0101t| Yadukta\u1E41 \u015Br\u012Bvij\xF1\u0101nabhairave</p><blockquote><p>Mah\u0101\u015B\u016Bny\u0101laye vahnau bh\u016Bt\u0101k\u1E63avi\u1E63ay\u0101dikam|<br> H\u016Byate manas\u0101 s\u0101ka\u1E41 sa homa\u1E25 srukca cetan\u0101||</p></blockquote><p>iti| \u015Ar\u012Btimirodgh\u0101\u1E6De&#39;pi</p><blockquote><p>Ya\u1E25 priyo ya\u1E25 suh\u1E5Bdbandhuryo d\u0101t\u0101 yo&#39;tivallabha\u1E25|<br> Tada\u1E45gabhak\u1E63a\u1E47\u0101ddevi hyutpatedgagan\u0101\u1E45gan\u0101||</p></blockquote><p>iti| Atra hi dehapram\u0101t\u1E5Bt\u0101pra\u015Bamanameva pi\u1E47\u1E0D\u0101rtha\u1E25| \u015Ar\u012Bmadbhagavadg\u012Bt\u0101svapi</p><blockquote><p>Sarv\u0101\u1E47\u012Bndriyakarm\u0101\u1E47i pr\u0101\u1E47akarm\u0101\u1E47i c\u0101pare|<br> \u0100tmasa\u1E41yamayog\u0101gnau juhvati j\xF1\u0101nad\u012Bpite||</p></blockquote><p>iti| Spande tu</p><blockquote><p>Yad\u0101 k\u1E63obha\u1E25 pral\u012Byeta tad\u0101 sy\u0101tparama\u1E41 padam|</p></blockquote><p>ityanenaiva sa\u1E45g\u1E5Bh\u012Btam| K\u1E63obho deh\u0101dyahampratyayar\u016Bpa iti hi tadv\u1E5Bttau bha\u1E6D\u1E6Da\u015Br\u012Bkalla\u1E6Da\u1E25||8||</p></div><hr><p>\u0427\u0442\u043E \u043A\u0430\u0441\u0430\u0435\u0442\u0441\u044F \u0442\u0430\u043A\u043E\u0433\u043E [Yog\u012B] <em>(\u012Bd\u1E5B\u015Basya asya)</em>, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0434\u043E\u0441\u0442\u0438\u0433 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u0438\u044F <em>(sambodhavata\u1E25)</em> \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u0433\u0440\u0443\u043F\u043F\u044B <em>(cakra)</em> \u0431\u0443\u043A\u0432 <em>(m\u0101t\u1E5Bk\u0101)</em>\u2014</p><blockquote><p><strong>\u0422\u0435\u043B\u043E [\u0447\u0435\u043B\u043E\u0432\u0435\u043A\u0430, \u0432 \u043A\u043E\u0442\u043E\u0440\u043E\u0433\u043E \u0431\u044B\u043B\u043E \u0438\u0437\u043B\u0438\u0442\u043E \u0432\u044B\u0448\u0435\u0443\u043F\u043E\u043C\u044F\u043D\u0443\u0442\u043E\u0435 \u043F\u0440\u043E\u0441\u0432\u0435\u0442\u043B\u0435\u043D\u0438\u0435] <em>(\u015Bar\u012Bram)</em>, [\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435\u043C <em>(havi\u1E25)</em>||8||</strong></p></blockquote><p>\u0422\u0435\u043B\u043E <em>(\u015Bar\u012Bram)</em>, \u0447\u044C\u044F \u043F\u0440\u0438\u0440\u043E\u0434\u0430 <em>(sva-r\u016Bpam)</em> \u2014 \u0433\u0440\u0443\u0431\u0430\u044F --\u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0430\u044F-- <em>(sth\u016Bla)</em>, \u0442\u043E\u043D\u043A\u0430\u044F <em>(s\u016Bk\u1E63ma)</em>, \u0438 \u0442.\u0434. <em>(\u0101di)</em> [\u0438] \u043A\u043E\u0442\u043E\u0440\u043E\u0435 *(yad)*\u043E\u0441\u044B\u043F\u0430\u043D\u043E <em>(abhi\u1E63iktam)</em> \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435\u043C \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0435\u0433\u043E --\u0442.\u0435. \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C \u042F-- <em>(pram\u0101t\u1E5Btvena)</em> \u0432\u043E \u0432\u0441\u0435\u0445 [\u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430\u0445] <em>(sarvai\u1E25)</em>, \u0432 \u0441\u043B\u0443\u0447\u0430\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u0433\u043E Yog\u012B <em>(mah\u0101-yogina\u1E25)</em>, \u043E\u043D\u043E <em>(tad)</em> [\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F] \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435\u043C <em>(havi\u1E25)</em>, \u0447\u0442\u043E\u0431\u044B \u0431\u044B\u0442\u044C \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u043D\u044B\u043C <em>(h\u016Byam\u0101nam)</em> \u0432\u044B\u0441\u0448\u0435\u043C\u0443 <em>(parasmin)</em> \u043E\u0433\u043D\u044E <em>(agnau)</em> \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(cit)</em>, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u043E\u043D \u043F\u043E\u0441\u0442\u043E\u044F\u043D\u043D\u043E \u043F\u043E\u0433\u0440\u0443\u0436\u0435\u043D <em>(sad\u0101 eva... abhinivi\u1E63\u1E6Datv\u0101t)</em> [\u0432 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435, \u0433\u0434\u0435 \u0442\u043E\u043B\u044C\u043A\u043E] Cit --\u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435-- <em>(cit)</em> [\u0432\u043E\u0441\u043F\u0440\u0438\u043D\u0438\u043C\u0430\u0435\u0442\u0441\u044F \u043A\u0430\u043A] \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439, \u0438\u043B\u0438 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0449\u0438\u0439 --m\u0101t\u1E5B-- <em>(m\u0101t\u1E5Bt\u0101)</em>, \u0438\u0437-\u0437\u0430 \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u044F <em>(pra\u015Bamanena)</em> [\u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F \u043E \u0442\u043E\u043C, \u0447\u0442\u043E] \u0442\u0435\u043B\u043E <em>(\u015Bar\u012Bra)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C, \u0438\u043B\u0438 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0449\u0438\u043C --pram\u0101t\u1E5B-- <em>(pram\u0101t\u1E5Bt\u0101)</em><sup>1</sup>|</p><p>\u042D\u0442\u043E <em>(yad)</em> \u0431\u044B\u043B\u043E \u0432\u044B\u0441\u043A\u0430\u0437\u0430\u043D\u043E <em>(uktam)</em> \u0432 \u0434\u043E\u0441\u0442\u043E\u0447\u0442\u0438\u043C\u043E\u043C Vij\xF1\u0101nabhairava <em>(\u015Br\u012B-vij\xF1\u0101nabhairave)</em>:</p><blockquote><p>&quot;[\u041A\u043E\u0433\u0434\u0430 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C] \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432 <em>(bh\u016Bta)</em>, \u0447\u0443\u0432\u0441\u0442\u0432 <em>(ak\u1E63a)</em>, \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 <em>(vi\u1E63aya)</em>, \u0438 \u0442.\u043F. <em>(\u0101dikam)</em>, \u0432\u043A\u043B\u044E\u0447\u0430\u044F \u0443\u043C <em>(manas\u0101 s\u0101kam)</em>, \u0432\u044B\u043B\u0438\u0432\u0430\u0435\u0442\u0441\u044F <em>(h\u016Byate)</em> \u0432 \u043E\u0433\u043E\u043D\u044C <em>(vahnau)</em>, \u0433\u0434\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u043B\u043D\u043E\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 <em>(\u0101laye)</em> \u0432\u0435\u043B\u0438\u043A\u043E\u0439 <em>(mah\u0101)</em> \u043F\u0443\u0441\u0442\u043E\u0442\u044B <em>(\u015B\u016Bnya)</em>, [\u0442\u043E\u0433\u0434\u0430] \u044D\u0442\u043E <em>(sa\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u043C] \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435\u043C <em>(homa\u1E25)</em>. \u041A\u043E\u0432\u0448 <em>(sruk ca)</em> [\u0435\u0441\u0442\u044C] Cetan\u0101 <em>(cetan\u0101... iti)</em><sup>2</sup>&quot;||</p></blockquote><p>\u0422\u0430\u043A\u0436\u0435 <em>(api)</em> \u0432 \u0443\u0432\u0430\u0436\u0430\u0435\u043C\u043E\u043C Timirodgh\u0101\u1E6Da <em>(\u015Br\u012B-timirodgh\u0101\u1E6De)</em>:</p><blockquote><p>&quot;[\u0412 \u0441\u043B\u0443\u0447\u0430\u0435] \u0442\u043E\u0433\u043E, \u043A\u0442\u043E <em>(ya\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0434\u043E\u0440\u043E\u0433\u0438\u043C <em>(priya\u1E25)</em>, \u043A\u0442\u043E <em>(ya\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0434\u0440\u0443\u0433\u043E\u043C <em>(suh\u1E5Bt)</em>, \u0440\u043E\u0434\u0441\u0442\u0432\u0435\u043D\u043D\u0438\u043A\u043E\u043C <em>(bandhu\u1E25)</em>, \u0436\u0435\u0440\u0442\u0432\u043E\u0432\u0430\u0442\u0435\u043B\u0435\u043C <em>(d\u0101t\u0101)</em>, [\u0438\u043B\u0438] \u043A\u0442\u043E <em>(ya\u1E25)</em> [\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F] \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u043E \u043B\u044E\u0431\u0438\u043C\u044B\u043C <em>(ati-vallabha\u1E25)</em>, \u041E \u0411\u043E\u0433\u0438\u043D\u044F <em>(devi)</em>, \u043F\u0443\u0442\u0435\u043C \u0443\u043D\u0438\u0447\u0442\u043E\u0436\u0435\u043D\u0438\u044F <em>(bhak\u1E63a\u1E47\u0101t)</em> [\u043F\u0440\u0435\u0434\u0441\u0442\u0430\u0432\u043B\u0435\u043D\u0438\u044F, \u0447\u0442\u043E \u0435\u0433\u043E] \u0442\u0435\u043B\u043E <em>(a\u1E45ga)</em> [\u0435\u0441\u0442\u044C] \u0422\u043E --\u0421\u0430\u043C\u043E\u0441\u0442\u044C-- <em>(tad)</em>, \u0416\u0435\u043D\u0449\u0438\u043D\u0430 --\u0442.\u0435. \u015Aakti-- <em>(a\u1E45gan\u0101)</em> \u0432 \u043F\u0440\u043E\u0441\u0442\u0440\u0430\u043D\u0441\u0442\u0432\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F <em>(gagan\u0101)</em> \u0432\u043E\u0437\u0432\u044B\u0448\u0430\u0435\u0442\u0441\u044F <em>(utpatet)</em>, \u043D\u0435\u0441\u043E\u043C\u043D\u0435\u043D\u043D\u043E <em>(hi... iti)</em>&quot;||</p></blockquote><p>\u0417\u0434\u0435\u0441\u044C <em>(atra hi)</em>, \u043E\u0431\u0449\u0435\u0435 <em>(pi\u1E47\u1E0Da)</em> \u0437\u043D\u0430\u0447\u0435\u043D\u0438\u0435 <em>(artha\u1E25)</em> [\u0435\u0441\u0442\u044C] \u043F\u0440\u0435\u043A\u0440\u0430\u0449\u0435\u043D\u0438\u0435 <em>(pra\u015Bamana eva)</em> [\u0438\u0434\u0435\u0438 \u043E \u0442\u043E\u043C, \u0447\u0442\u043E] \u0442\u0435\u043B\u043E <em>(deha)</em> \u2014 \u044D\u0442\u043E \u041F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u0439, \u0438\u043B\u0438 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0449\u0438\u0439 --Pram\u0101t\u1E5B-- <em>(pram\u0101t\u1E5Bt\u0101)</em>|</p><p>\u0414\u0430\u0436\u0435 <em>(api)</em> \u0432 \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u043E\u0439 Bhagavadg\u012Bt\u0101 <em>(\u015Br\u012Bmat-bhagavadg\u012Bt\u0101su)</em>:</p><blockquote><p>&quot;\u0414\u0440\u0443\u0433\u0438\u0435 <em>(apare)</em> \u043F\u043E\u0434\u043D\u043E\u0441\u044F\u0442 <em>(juhvati)</em> \u0432\u0441\u0435 <em>(sarv\u0101\u1E47i)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karm\u0101\u1E47i)</em> indriya-s --\u0421\u0438\u043B\u044B \u0432\u043E\u0441\u043F\u0440\u0438\u044F\u0442\u0438\u044F \u0438 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F-- <em>(indriya)</em> \u0438 <em>(ca)</em> \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u044F <em>(karm\u0101\u1E47i)</em> \u0436\u0438\u0437\u043D\u0435\u043D\u043D\u044B\u0445 \u044D\u043D\u0435\u0440\u0433\u0438\u0439 <em>(pr\u0101\u1E47a)</em> \u043E\u0433\u043D\u044E <em>(agnau)</em> \u0419\u043E\u0433\u0438 <em>(yoga)</em> \u0441\u0430\u043C\u043E\u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044F --\u0442\u0430\u043A\u0436\u0435 &quot;\u043A\u043E\u043D\u0442\u0440\u043E\u043B\u044F \u0443\u043C\u0430&quot;-- <em>(\u0101tma-sa\u1E41yama)</em>, \u0440\u0430\u0437\u043E\u0436\u0436\u0435\u043D\u043E\u043C\u0443 <em>(d\u012Bpite)</em> \u0437\u043D\u0430\u043D\u0438\u0435\u043C <em>(j\xF1\u0101na... iti)</em>&quot;||<br> [\u0421\u043C. Bhagavadg\u012Bt\u0101 IV, 27]</p></blockquote><p>\u0412 Spandak\u0101rik\u0101-s <em>(spande)</em>, [\u044D\u0442\u043E \u0436\u0435 \u0443\u0447\u0435\u043D\u0438\u0435] \u0431\u044B\u043B\u043E \u043E\u0431\u043E\u0431\u0449\u0435\u043D\u043E <em>(sa\u1E45g\u1E5Bh\u012Btam)</em> \u044D\u0442\u0438\u043C [\u0430\u0444\u043E\u0440\u0438\u0437\u043C\u043E\u043C] <em>(anena eva)</em>:</p><blockquote><p>&quot;\u041A\u043E\u0433\u0434\u0430 <em>(yad\u0101)</em> \u0432\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 (\u0443\u043C\u0430) <em>(k\u1E63obha\u1E25)</em>... \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0438\u0441\u0447\u0435\u0437\u0430\u0435\u0442 <em>(pral\u012Byeta)</em>, \u0442\u043E\u0433\u0434\u0430 <em>(tad\u0101)</em> \u0412\u044B\u0441\u0448\u0435\u0435 <em>(paramam)</em> \u0421\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 <em>(padam)</em> \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E <em>(sy\u0101t... iti)</em>&quot;|<br> [\u0421\u043C. Spandak\u0101rik\u0101-s I, 9]</p></blockquote><p>&quot;\u0412\u043E\u0437\u0431\u0443\u0436\u0434\u0435\u043D\u0438\u0435 <em>(k\u1E63obha\u1E25)</em> \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F <em>(r\u016Bpa\u1E25)</em> \u0438\u0434\u0435\u0435\u0439 <em>(pratyaya)</em>, \u0447\u0442\u043E \u0421\u0430\u043C\u043E\u0441\u0442\u044C --\u0442.\u0435. &#39;\u042F&#39;-- <em>(aham)</em> \u2014 \u044D\u0442\u043E \u0442\u0435\u043B\u043E <em>(deha)</em>, \u0438 \u0442.\u0434. <em>(\u0101di... iti)</em>&quot;, [\u0441\u043E\u0433\u043B\u0430\u0441\u043D\u043E \u0442\u043E\u043C\u0443, \u0447\u0442\u043E] \u043F\u043E\u0447\u0442\u0435\u043D\u043D\u044B\u0439 <em>(bha\u1E6D\u1E6Da-\u015Br\u012B)</em> Kalla\u1E6Da <em>(kalla\u1E6Da\u1E25)</em> [\u043D\u0430\u043F\u0438\u0441\u0430\u043B] \u0432 \u0441\u0432\u043E\u0435\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 [\u043D\u0430 Spandak\u0101rik\u0101-s] <em>(hi tad-v\u1E5Bttau)</em>||8||</p><hr><ol><li>\u0412 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435 \u043F\u043E\u0434 \u0442\u0435\u043B\u043E\u043C \u043F\u043E\u0434\u0440\u0430\u0437\u0443\u043C\u0435\u0432\u0430\u0435\u0442\u0441\u044F \u043D\u0435 \u0442\u043E\u043B\u044C\u043A\u043E \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u043E\u0435, \u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u0442\u043E\u043D\u043A\u043E\u0435, \u043F\u0440\u0438\u0447\u0438\u043D\u043D\u043E\u0435 \u0438 \u0441\u0443\u043F\u0440\u0430\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435 \u0442\u0435\u043B\u0430. \u0421\u0443\u043F\u0440\u0430\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435 \u0442\u0435\u043B\u043E \u2014 \u044D\u0442\u043E \u0411\u0438\u043D\u0434\u0443, \u0442\u043E\u0447\u043A\u0430 \u0441\u0438\u043D\u0435\u0433\u043E \u0421\u0432\u0435\u0442\u0430, \u0433\u0434\u0435 \u043E\u0433\u0440\u043E\u043C\u043D\u0430\u044F \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u0430\u043A \u043A\u0440\u043E\u0448\u0435\u0447\u043D\u0430\u044F \u043C\u0430\u0441\u0441\u0430 \u0447\u0438\u0441\u0442\u043E\u0433\u043E \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u044F. \u042D\u0442\u0430 \u0441\u043E\u0432\u043E\u043A\u0443\u043F\u043D\u043E\u0441\u0442\u044C \u0447\u0435\u0442\u044B\u0440\u0435\u0445 \u0442\u0435\u043B \u043E\u0431\u044B\u0447\u043D\u043E \u043F\u0440\u043E\u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u043E\u0441\u044B\u043F\u0430\u043D\u043D\u043E\u0439&quot; \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C \u044F, \u0438\u043B\u0438 \u044D\u0433\u043E, \u0442.\u0435 \u043F\u043E\u0434\u0430\u0432\u043B\u044F\u044E\u0449\u0435\u0435 \u0431\u043E\u043B\u044C\u0448\u0438\u043D\u0441\u0442\u0432\u043E \u043B\u044E\u0434\u0435\u0439 \u0443\u0431\u0435\u0436\u0434\u0435\u043D\u044B, \u0447\u0442\u043E \u043E\u043D\u0438 \u0435\u0441\u0442\u044C \u0442\u0435\u043B\u0430. \u041E\u0434\u043D\u0430\u043A\u043E, \u044D\u0442\u043E \u043D\u0435 \u043E\u0442\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u0432 \u0432\u0435\u043B\u0438\u043A\u043E\u043C\u0443 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0443, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0434\u0430\u0436\u0435 \u0434\u0443\u0445\u043E\u0432\u043D\u043E\u0435 \u0442\u0435\u043B\u043E (\u0441\u0443\u043F\u0440\u0430\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435), \u044F\u0432\u043B\u044F\u044E\u0449\u0435\u0435\u0441\u044F \u043E\u0447\u0435\u043D\u044C \u0442\u043E\u043D\u043A\u0438\u043C \u043F\u043E \u0441\u0440\u0430\u0432\u043D\u0435\u043D\u0438\u044E \u0441 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u043C \u0442\u0435\u043B\u043E\u043C, \u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u0441\u044F \u043F\u043E\u0434\u043D\u043E\u0448\u0435\u043D\u0438\u0435\u043C, \u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0434\u043E\u043B\u0436\u043D\u043E \u0431\u044B\u0442\u044C \u043F\u0440\u0435\u0434\u043B\u043E\u0436\u0435\u043D\u043E \u043E\u0433\u043D\u044E \u0411\u043E\u0433\u0430, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 \u043A\u0430\u043A \u043E\u0447\u0438\u0449\u0435\u043D\u043D\u043E\u0435 \u043C\u0430\u0441\u043B\u043E, \u0438 \u0442.\u043F. \u043F\u043E\u0434\u043D\u043E\u0441\u0438\u0442\u0441\u044F \u043E\u0433\u043D\u044E \u0432\u043E \u0432\u0440\u0435\u043C\u044F \u0436\u0435\u0440\u0442\u0432\u043E\u043F\u0440\u0438\u043D\u043E\u0448\u0435\u043D\u0438\u044F \u0436\u0440\u0435\u0446\u043E\u043C. \u041F\u043E\u0447\u0435\u043C\u0443? \u041F\u043E\u0442\u043E\u043C\u0443 \u0447\u0442\u043E \u0441\u0432\u044F\u0442\u043E\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u043E \u0434\u043E\u0441\u0442\u0438\u0433\u043B\u043E \u0446\u0435\u043B\u0438 \u0436\u0438\u0437\u043D\u0438, \u043E\u0441\u043E\u0437\u043D\u0430\u0432, \u0447\u0442\u043E \u0438\u0441\u0442\u0438\u043D\u043D\u044B\u043C \u043F\u043E\u0437\u043D\u0430\u044E\u0449\u0438\u043C, \u0438\u043B\u0438 \u0438\u0441\u043F\u044B\u0442\u044B\u0432\u0430\u044E\u0449\u0438\u043C \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F Cit (\u0412\u044B\u0441\u0448\u0435\u0435 \u042F/\u0421\u0430\u043C\u043E\u0441\u0442\u044C), \u0430 \u043D\u0435 \u0442\u0435\u043B\u043E. \u0422\u0430\u043A, \u043F\u043E\u0441\u043B\u0435 \u043E\u043A\u043E\u043D\u0447\u0430\u0442\u0435\u043B\u044C\u043D\u043E\u0433\u043E \u041E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u0438\u044F, \u0442\u0430\u043A\u043E\u0439 \u0432\u043E\u0437\u0432\u044B\u0448\u0435\u043D\u043D\u044B\u0439 \u0447\u0435\u043B\u043E\u0432\u0435\u043A \u0431\u043E\u043B\u044C\u0448\u0435 \u043D\u0435 \u0438\u043D\u0442\u0435\u0440\u0435\u0441\u0443\u0435\u0442\u0441\u044F \u0441\u0443\u0434\u044C\u0431\u043E\u0439 \u0441\u0432\u043E\u0435\u0433\u043E \u0442\u0435\u043B\u0430. \u041F\u043E\u044D\u0442\u043E\u043C\u0443, \u043E\u043D \u043F\u0435\u0440\u0435\u0434\u0430\u0435\u0442 \u0432\u0441\u0435 \u0432 \u0440\u0443\u043A\u0438 \u0411\u043E\u0433\u0430.</li></ol><p>\u0411\u043E\u0436\u0435\u0441\u0442\u0432\u0435\u043D\u043D\u043E\u0435 \u042F \u043C\u043E\u0436\u0435\u0442 \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u0435\u0433\u043E \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u0442\u044C \u0441\u0432\u043E\u0435 \u0442\u0435\u043B\u043E, \u0438 \u044D\u0442\u043E \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u0442\u0441\u044F &quot;J\u012Bvanmukti&quot;, \u0438\u043B\u0438 \u041E\u043D \u043C\u043E\u0436\u0435\u0442 \u0437\u0430\u0441\u0442\u0430\u0432\u0438\u0442\u044C \u043E\u0442\u043A\u0430\u0437\u0430\u0442\u044C\u0441\u044F \u043E\u0442 \u043D\u0435\u0433\u043E (Videhamukti). \u0412 \u043E\u0431\u0449\u0435\u043C, \u044D\u0442\u0438 \u0441\u0432\u044F\u0442\u044B\u0435 \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430 \u043E\u0441\u0442\u0430\u044E\u0442\u0441\u044F \u0441\u0440\u0435\u0434\u0438 \u043B\u044E\u0434\u0435\u0439, \u0441\u043E\u0445\u0440\u0430\u043D\u0438\u0432 \u0432\u0441\u0435 \u0441\u0432\u043E\u0438 \u0447\u0435\u0442\u044B\u0440\u0435 \u0442\u0435\u043B\u0430, \u0438\u043B\u0438 \u043E\u043D\u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u0442 \u0442\u0440\u0438, \u0434\u0432\u0430 \u0438\u043B\u0438 \u0434\u0430\u0436\u0435 \u043E\u0434\u043D\u043E (\u0441\u0443\u043F\u0440\u0430\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435 \u0442\u0435\u043B\u043E); \u043B\u0438\u0431\u043E, \u043E\u043D\u0438 \u043D\u0435 \u043E\u0441\u0442\u0430\u0432\u044F\u0442 \u043D\u0438\u043A\u0430\u043A\u043E\u0433\u043E \u0442\u0435\u043B\u0430 \u0438 \u0441\u043E\u043B\u044C\u044E\u0442\u0441\u044F \u0441 \u0431\u0435\u0441\u0444\u043E\u0440\u043C\u0435\u043D\u043D\u044B\u043C Cit. \u041A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u044E\u0442 \u0447\u0435\u0442\u044B\u0440\u0435 \u0442\u0435\u043B\u0430 \u0438\u043B\u0438, \u0434\u0430\u0436\u0435, \u043E\u0434\u043D\u043E, \u044D\u0442\u043E \u0434\u0435\u043B\u0430\u0435\u0442\u0441\u044F \u0432\u0441\u0435\u0433\u0434\u0430 \u043D\u0430 \u0431\u043B\u0430\u0433\u043E \u043B\u044E\u0434\u0435\u0439 \u0438\u0437-\u0437\u0430 \u0441\u043E\u0441\u0442\u0440\u0430\u0434\u0430\u043D\u0438\u044F \u0413\u043E\u0441\u043F\u043E\u0434\u0430. \u041D\u0435\u043A\u043E\u0442\u043E\u0440\u044B\u0435 \u0438\u0437 \u043D\u0438\u0445 \u0441\u043E\u0445\u0440\u0430\u043D\u044F\u044E\u0442 \u0441\u0432\u043E\u0438 \u0442\u0435\u043B\u0430 \u043D\u0430 \u043D\u0435\u043A\u043E\u0442\u043E\u0440\u043E\u0435 \u0432\u0440\u0435\u043C\u044F, \u0438 \u043A\u043E\u0433\u0434\u0430 \u043E\u043D\u0438 \u043F\u043E\u043A\u0438\u0434\u0430\u044E\u0442 \u0441\u0432\u043E\u0438 \u0444\u0438\u0437\u0438\u0447\u0435\u0441\u043A\u0438\u0435 \u0442\u0435\u043B\u0430 \u0432 \u043C\u043E\u043C\u0435\u043D\u0442 \u0441\u043C\u0435\u0440\u0442\u0438, \u043E\u043D\u0438 \u043E\u0441\u0442\u0430\u0432\u043B\u044F\u044E\u0442 \u0442\u043E\u043B\u044C\u043A\u043E \u0441\u0443\u043F\u0440\u0430\u043A\u0430\u0443\u0437\u0430\u043B\u044C\u043D\u043E\u0435 \u0442\u0435\u043B\u043E, \u0447\u0442\u043E\u0431\u044B \u0436\u0438\u0442\u044C \u0432 Siddhaloka (\u043C\u0438\u0440\u0435 \u0441\u043E\u0432\u0435\u0440\u0448\u0435\u043D\u043D\u044B\u0445 \u0441\u0443\u0449\u0435\u0441\u0442\u0432). \u0422\u0430\u043A \u0438\u043B\u0438 \u0438\u043D\u0430\u0447\u0435, \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u043E\u0441\u0432\u043E\u0431\u043E\u0436\u0434\u0435\u043D\u043D\u043E\u0439 \u0434\u0443\u0448\u0438, \u0432\u043E\u043E\u0431\u0449\u0435 \u043D\u0435\u0442 \u043D\u0438\u043A\u0430\u043A\u0438\u0445 \u0441\u043E\u0445\u0440\u0430\u043D\u0435\u043D\u043D\u044B\u0445 \u0438\u043B\u0438 \u043E\u0442\u0431\u0440\u043E\u0448\u0435\u043D\u043D\u044B\u0445 \u0442\u0435\u043B. \u042D\u0442\u0438 \u043F\u0440\u043E\u0446\u0435\u0441\u0441\u044B \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u044F \u0442\u043E\u043B\u044C\u043A\u043E \u0441 \u0442\u043E\u0447\u043A\u0438 \u0437\u0440\u0435\u043D\u0438\u044F \u043E\u0433\u0440\u0430\u043D\u0438\u0447\u0435\u043D\u043D\u043E\u0433\u043E \u0441\u0443\u0449\u0435\u0441\u0442\u0432\u0430, \u043E\u0441\u044B\u043F\u0430\u043D\u043D\u043E\u0433\u043E \u043E\u0441\u043E\u0437\u043D\u0430\u043D\u0438\u0435\u043C \u044F. \u041D\u0443, \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u0433\u043E\u0432\u043E\u0440\u0438\u0442\u044C \u043E\u0431 \u044D\u0442\u0438\u0445 \u0442\u0430\u0439\u043D\u0430\u0445!</p><ol start="2"><li>\u041C\u043D\u0435 \u043F\u0440\u0438\u0434\u0435\u0442\u0441\u044F \u043E\u0431\u044A\u044F\u0441\u043D\u0438\u0442\u044C \u0432\u0430\u043C \u044D\u0442\u0443 \u0441\u043B\u043E\u0436\u043D\u0443\u044E \u0441\u0442\u0440\u043E\u0444\u0443, \u043F\u043E \u043A\u0440\u0430\u0439\u043D\u0435\u0439 \u043C\u0435\u0440\u0435 \u043D\u0435\u043C\u043D\u043E\u0433\u043E: \u0422\u0435\u0440\u043C\u0438\u043D &quot;\u0101laye&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u0432 \u0101laya&quot;. \u0415\u0441\u043B\u0438 \u0432\u044B \u0431\u0443\u0434\u0435\u0442\u0435 \u0438\u0441\u043A\u0430\u0442\u044C \u0441\u043B\u043E\u0432\u043E &quot;\u0101laya&quot; \u0432 \u0441\u043B\u043E\u0432\u0430\u0440\u0435, \u0432\u044B \u043F\u043E\u043B\u0443\u0447\u0438\u0442\u0435 &quot;\u0441\u043E\u0441\u0443\u0434, \u0434\u043E\u043C, \u0436\u0438\u043B\u0438\u0449\u0435 \u0438 \u0442.\u0434.&quot;. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u0437\u0434\u0435\u0441\u044C \u044D\u0442\u043E \u0434\u043E\u043B\u0436\u043D\u043E \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0438\u0440\u043E\u0432\u0430\u0442\u044C\u0441\u044F \u043A\u0430\u043A &quot;\u0101 + laya&quot;, \u0438\u043B\u0438 &quot;\u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E + \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435&quot;. \u0414\u0440\u0443\u0433\u0438\u043C\u0438 \u0441\u043B\u043E\u0432\u0430\u043C\u0438, \u0447\u0430\u0441\u0442\u0438\u0446\u0430 &quot;\u0101&quot; \u0440\u0430\u0432\u043D\u0430 &quot;samant\u0101t&quot; (\u0432\u0441\u0435\u0446\u0435\u043B\u043E, \u043F\u043E\u043B\u043D\u043E\u0441\u0442\u044C\u044E \u0438 \u0442.\u043F.). \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u043A\u043E\u043D\u0435\u0447\u043D\u044B\u0439 \u0440\u0435\u0437\u0443\u043B\u044C\u0442\u0430\u0442 \u2014 \u043D\u0435 &quot;\u043F\u043E\u043B\u043D\u043E\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435&quot;, \u0430 &quot;\u0442\u043E, \u0433\u0434\u0435 \u0438\u043C\u0435\u0435\u0442 \u043C\u0435\u0441\u0442\u043E \u043F\u043E\u043B\u043D\u043E\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435&quot;, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u044D\u0442\u043E \u0441\u043B\u043E\u0432\u043E \u0440\u0430\u0431\u043E\u0442\u0430\u0435\u0442 \u043A\u0430\u043A Bahuvr\u012Bhi. OK, \u044D\u0442\u0430 \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u044F \u043D\u0435 \u0431\u044B\u043B\u0430 \u043C\u043E\u0435\u0439 \u0431\u043B\u0435\u0441\u0442\u044F\u0449\u0435\u0439 \u0438\u0434\u0435\u0435\u0439, \u043A\u043E\u0433\u0434\u0430 \u044F \u043F\u0440\u043E\u0441\u043D\u0443\u043B\u0441\u044F \u0441\u0435\u0433\u043E\u0434\u043D\u044F \u0443\u0442\u0440\u043E\u043C. \u041D\u0435\u0442, \u043E\u043D\u0430 \u043F\u0440\u0438\u043D\u0430\u0434\u043B\u0435\u0436\u0438\u0442 \u0442\u043E\u043C\u0443 \u0436\u0435 \u0441\u0432\u044F\u0442\u043E\u043C\u0443, \u043A\u043E\u0442\u043E\u0440\u044B\u0439 \u0441\u0435\u0439\u0447\u0430\u0441 \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442 \u043D\u0430\u0441\u0442\u043E\u044F\u0449\u0435\u0435 \u041F\u0438\u0441\u0430\u043D\u0438\u0435, \u0442.\u0435. \u041A\u0448\u0435\u043C\u0430\u0440\u0430\u0434\u0436\u0435. \u041E\u043D \u0442\u0430\u043A\u0436\u0435 \u043D\u0430\u043F\u0438\u0441\u0430\u043B \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0439 \u043D\u0430 Vij\xF1\u0101nabhairava. \u0412 \u0441\u0442\u0440\u043E\u0444\u0435 149 (\u0442\u043E\u0439, \u043A\u043E\u0442\u043E\u0440\u0430\u044F \u0443\u043A\u0430\u0437\u0430\u043D\u0430 \u0437\u0434\u0435\u0441\u044C), \u043E\u043D \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0438\u0440\u0443\u0435\u0442:</li></ol><p>&quot;\u092E\u0939\u093E\u0936\u0942\u0928\u094D\u092F\u0938\u094D\u092F \u0936\u0942\u0928\u094D\u092F\u093E\u0924\u093F\u0936\u0942\u0928\u094D\u092F\u092A\u0926\u0938\u094D\u092F \u0906 \u0938\u092E\u0928\u094D\u0924\u093E\u0932\u094D\u0932\u092F\u094B \u092F\u0924\u094D\u0930 \u092A\u0930\u0924\u0924\u094D\u0924\u094D\u0935\u093E\u0924\u094D\u092E\u0928\u093F \u0935\u0939\u094D\u0928\u094C...&quot; - &quot;Mah\u0101\u015B\u016Bnyasya \u015B\u016Bny\u0101ti\u015B\u016Bnyapadasya \u0101 samant\u0101llayo yatra paratattv\u0101tmani vahnau...&quot; \u2014 &quot;\u0412 \u043E\u0433\u043D\u0435 (\u0432\u044B\u0441\u0448\u0430\u044F \u0442\u0430\u0442\u0442\u0432\u0430, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F, \u0442.\u0435. \u015Aiva), \u0433\u0434\u0435 \u043F\u0440\u043E\u0438\u0441\u0445\u043E\u0434\u0438\u0442 \u043F\u043E\u043B\u043D\u043E\u0435 \u0440\u0430\u0441\u0442\u0432\u043E\u0440\u0435\u043D\u0438\u0435 \u0432\u0435\u043B\u0438\u043A\u043E\u0439 \u043F\u0443\u0441\u0442\u043E\u0442\u044B, \u0430 \u0438\u043C\u0435\u043D\u043D\u043E, \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0438 \u043F\u0443\u0441\u0442\u043E\u0442\u044B \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u043F\u0443\u0441\u0442\u043E\u0442\u044B...&quot;</p><p>\u0422\u0435\u0440\u043C\u0438\u043D &quot;mah\u0101\u015B\u016Bnya&quot;, \u0438\u043B\u0438 \u0432\u0435\u043B\u0438\u043A\u0430\u044F \u043F\u0443\u0441\u0442\u043E\u0442\u0430, \u043E\u0445\u0430\u0440\u0430\u043A\u0442\u0435\u0440\u0438\u0437\u043E\u0432\u0430\u043D \u0441\u0432\u044F\u0442\u044B\u043C, \u043A\u0430\u043A &quot;\u0936\u0942\u0928\u094D\u092F\u093E\u0924\u093F\u0936\u0942\u0928\u094D\u092F\u092A\u0926&quot; - &quot;\u015B\u016Bny\u0101ti\u015B\u016Bnyapada&quot;, \u0438\u043B\u0438 \u0441\u043E\u0441\u0442\u043E\u044F\u043D\u0438\u0435 \u043F\u0443\u0441\u0442\u043E\u0442\u044B \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u043F\u0443\u0441\u0442\u043E\u0442\u044B. K\u1E63emar\u0101ja \u043D\u0435 \u043E\u0431\u044A\u044F\u0441\u043D\u044F\u0435\u0442 \u0433\u043B\u0443\u0431\u043E\u043A\u043E \u044D\u0442\u043E\u0442 \u0442\u0435\u0440\u043C\u0438\u043D \u0442\u0430\u043C, \u043D\u043E \u0443\u043A\u0430\u0437\u044B\u0432\u0430\u0435\u0442 \u0432 \u0441\u0432\u043E\u0435\u043C \u043A\u043E\u043C\u043C\u0435\u043D\u0442\u0430\u0440\u0438\u0438 \u043D\u0430 Svacchandatantra (\u043E\u0447\u0435\u043D\u044C \u0432\u0430\u0436\u043D\u043E\u043C \u0442\u0430\u043D\u0442\u0440\u0438\u0447\u0435\u0441\u043A\u043E\u043C \u041F\u0438\u0441\u0430\u043D\u0438\u0438), \u0447\u0442\u043E &quot;\u015B\u016Bny\u0101ti\u015B\u016Bnya&quot; (\u043F\u0443\u0441\u0442\u043E\u0442\u0430 \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u043F\u0443\u0441\u0442\u043E\u0442\u044B) \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F &quot;\u092E\u0939\u093E\u092E\u093E\u092F\u093E&quot; - &quot;Mah\u0101m\u0101y\u0101&quot; (\u0432\u0435\u043B\u0438\u043A\u043E\u0439 M\u0101y\u0101), \u0438 \u043F\u043E\u0434\u043E\u0431\u043D\u0430\u044F \u0438\u043D\u0442\u0435\u0440\u043F\u0440\u0435\u0442\u0430\u0446\u0438\u044F \u043C\u043E\u0436\u0435\u0442 \u0431\u044B\u0442\u044C \u0442\u0430\u043A\u0436\u0435 \u0438\u0441\u043F\u043E\u043B\u044C\u0437\u043E\u0432\u0430\u043D\u0430 \u0432 \u044D\u0442\u043E\u043C \u043A\u043E\u043D\u0442\u0435\u043A\u0441\u0442\u0435. \u0422\u0430\u0442\u0442\u0432\u0430, \u0438\u043B\u0438 \u043A\u0430\u0442\u0435\u0433\u043E\u0440\u0438\u044F, \u043D\u0430\u0437\u044B\u0432\u0430\u0435\u043C\u0430\u044F &quot;M\u0101y\u0101&quot; \u2014 \u0448\u0435\u0441\u0442\u0430\u044F. \u042D\u0442\u0430 M\u0101y\u0101 \u0435\u0441\u0442\u044C \u043F\u0443\u0441\u0442\u043E\u0442\u0430. \u041F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 &quot;Mah\u0101m\u0101y\u0101&quot; \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u0434\u0435\u0439\u0441\u0442\u0432\u0443\u044E\u0449\u0435\u0439 \u0432 \u0442\u0430\u0442\u0442\u0432\u0430\u0445 \u0441 \u0442\u0440\u0435\u0442\u044C\u0435\u0439 \u043F\u043E \u043F\u044F\u0442\u0443\u044E, \u0442\u043E \u043C\u043E\u0436\u043D\u043E \u0441\u043A\u0430\u0437\u0430\u0442\u044C, \u0447\u0442\u043E \u043E\u043D\u0430, \u0432 \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E\u0441\u0442\u0438, \u2014 \u043F\u0443\u0441\u0442\u043E\u0442\u0430 \u0437\u0430 \u043F\u0440\u0435\u0434\u0435\u043B\u0430\u043C\u0438 \u043F\u0443\u0441\u0442\u043E\u0442\u044B. Mah\u0101m\u0101y\u0101 \u043F\u0440\u043E\u0438\u0437\u0432\u043E\u0434\u0438\u0442 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F, \u043D\u043E \u0438\u0441\u043A\u043B\u044E\u0447\u0430\u0435\u0442 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u042F \u0435\u0441\u0442\u044C \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F - \u0442.\u0435. \u042F \u043E\u0442\u043B\u0438\u0447\u0435\u043D, \u043D\u043E \u043D\u0435 \u043E\u0442\u0434\u0435\u043B\u0435\u043D \u043E\u0442 \u043D\u0435\u0435), \u0432 \u0442\u043E \u0432\u0440\u0435\u043C\u044F \u043A\u0430\u043A M\u0101y\u0101 \u043F\u043E\u0440\u043E\u0436\u0434\u0430\u0435\u0442 \u0438 \u0440\u0430\u0437\u043B\u0438\u0447\u0438\u044F, \u0438 \u0440\u0430\u0437\u0434\u0435\u043B\u0435\u043D\u0438\u0435 (\u043D\u0430\u043F\u0440\u0438\u043C\u0435\u0440, \u042F \u043D\u0435 \u0435\u0441\u0442\u044C \u0432\u0441\u0435\u043B\u0435\u043D\u043D\u0430\u044F - \u0442.\u0435. \u042F \u043E\u0442\u043B\u0438\u0447\u0435\u043D \u0438 \u043E\u0442\u0434\u0435\u043B\u0435\u043D \u043E\u0442 \u043D\u0435\u0435). OK, \u0442\u0435\u043F\u0435\u0440\u044C \u0434\u043E\u0441\u0442\u0430\u0442\u043E\u0447\u043D\u043E \u044F\u0441\u043D\u043E, \u044F \u0434\u0443\u043C\u0430\u044E.</p><p>&quot;Cetan\u0101&quot; \u2014 \u044D\u0442\u043E &quot;sr\xFAk&quot;, \u0438\u043B\u0438 \u043A\u043E\u0432\u0448, \u043F\u043E\u0441\u043A\u043E\u043B\u044C\u043A\u0443 \u0442\u043E\u0447\u043D\u043E \u043A\u0430\u043A \u043A\u043E\u0432\u0448 \u0432\u044B\u043B\u0438\u0432\u0430\u0435\u0442 \u043E\u0447\u0438\u0449\u0435\u043D\u043D\u043E\u0435 \u043C\u0430\u0441\u043B\u043E, \u0438 \u0442.\u043F. \u0432 \u0436\u0435\u0440\u0442\u0432\u0435\u043D\u043D\u044B\u0439 \u043E\u0433\u043E\u043D\u044C, \u0442\u043E\u0447\u043D\u043E \u0442\u0430\u043A\u0436\u0435 Cetan\u0101 \u043B\u044C\u0435\u0442 Citta (\u0443\u043C \u0438 \u0435\u0433\u043E \u043F\u043E\u0442\u043E\u043C\u0441\u0442\u0432\u043E \u0432 \u0444\u043E\u0440\u043C\u0435 \u044D\u043B\u0435\u043C\u0435\u043D\u0442\u043E\u0432, \u0447\u0443\u0432\u0441\u0442\u0432, \u043E\u0431\u044A\u0435\u043A\u0442\u043E\u0432 \u0447\u0443\u0432\u0441\u0442\u0432 \u0438 \u043F\u0440.) \u0432 Cit, \u0438\u043B\u0438 \u0447\u0438\u0441\u0442\u043E\u0435 \u0421\u043E\u0437\u043D\u0430\u043D\u0438\u0435 (\u015Aiva). \u0425\u043E\u0442\u044F \u0442\u0435\u0440\u043C\u0438\u043D &quot;Cetan\u0101&quot; \u043D\u0435\u0432\u043E\u0437\u043C\u043E\u0436\u043D\u043E \u0442\u043E\u0447\u043D\u043E \u043F\u0435\u0440\u0435\u0432\u0435\u0441\u0442\u0438 \u043D\u0430 \u0430\u043D\u0433\u043B\u0438\u0439\u0441\u043A\u0438\u0439 (\u0438\u043B\u0438 \u043A\u0430\u043A\u043E\u0439-\u043B\u0438\u0431\u043E \u0434\u0440\u0443\u0433\u043E\u0439 \u044F\u0437\u044B\u043A), K\u1E63emar\u0101ja \u0443\u043F\u043E\u043C\u0438\u043D\u0430\u0435\u0442, \u0447\u0442\u043E:</p><p>&quot;... \u091A\u0947\u0924\u0928\u093E \u0935\u093F\u0936\u094D\u0935\u093E\u0928\u0941\u0938\u0928\u094D\u0927\u093E\u0924\u094D\u0930\u0940 \u0936\u0915\u094D\u0924\u093F\u0930\u0947\u0935 \u0938\u094D\u0930\u0941\u0915\u094D...&quot; - &quot;... cetan\u0101 vi\u015Bv\u0101nusandh\u0101tr\u012B \u015Baktireva sruk...&quot; \u2014 &quot;Cetan\u0101, \u015Aakti, \u0438\u043B\u0438 \u0421\u0438\u043B\u0430, \u0438\u0441\u0441\u043B\u0435\u0434\u0443\u044E\u0449\u0430\u044F \u0432\u0441\u0435, \u0434\u0435\u0439\u0441\u0442\u0432\u0438\u0442\u0435\u043B\u044C\u043D\u043E \u044F\u0432\u043B\u044F\u0435\u0442\u0441\u044F \u043A\u043E\u0432\u0448\u043E\u043C&quot;</p><p>\u041F\u043E\u043C\u0438\u043C\u043E &quot;\u0438\u0441\u0441\u043B\u0435\u0434\u043E\u0432\u0430\u043D\u0438\u044F&quot;, \u0442\u0435\u0440\u043C\u0438\u043D &quot;anusandh\u0101tr\u012B&quot; \u043E\u0437\u043D\u0430\u0447\u0430\u0435\u0442 &quot;\u043E\u0431\u044A\u0435\u0434\u0438\u043D\u044F\u044E\u0449\u0438\u0439&quot;, \u043A\u043E\u0440\u043E\u0447\u0435, Cetan\u0101 \u0441\u043E\u0435\u0434\u0438\u043D\u044F\u0435\u0442 \u0443\u043C, \u0447\u0443\u0432\u0441\u0442\u0432\u0430 \u0438 \u043F\u0440. \u0441 \u0412\u0435\u043B\u0438\u043A\u0438\u043C \u0413\u043E\u0441\u043F\u043E\u0434\u043E\u043C. \u0425\u043E\u0440\u043E\u0448\u043E, \u044F \u0434\u043E\u043B\u0436\u0435\u043D \u043E\u0441\u0442\u0430\u043D\u043E\u0432\u0438\u0442\u044C\u0441\u044F \u0437\u0434\u0435\u0441\u044C, \u0438\u043B\u0438 \u044D\u0442\u043E \u043F\u0440\u0438\u043C\u0435\u0447\u0430\u043D\u0438\u0435 \u0431\u0443\u0434\u0435\u0442 \u0441\u043B\u0438\u0448\u043A\u043E\u043C \u0434\u043B\u0438\u043D\u043D\u044B\u043C. \u0422\u0435\u043C \u043D\u0435 \u043C\u0435\u043D\u0435\u0435, \u044F \u043B\u0438\u0448\u044C \u043F\u0440\u0438\u043A\u043E\u0441\u043D\u0443\u043B\u0441\u044F \u043A \u043F\u043E\u0432\u0435\u0440\u0445\u043D\u043E\u0441\u0442\u0438.</p></div>',1),u=[i];function p(r,n,q,s,h,d){return m(),e("div",null,u)}var v=a(o,[["render",p]]);export{l as __pageData,v as default};
